module f_module (
    input [2:0] a,
    output reg not_y
);

    always @(*) begin
        case (a)
            3'b000: not_y = 1;
            3'b001: not_y = 0;
            3'b010: not_y = 1;
            3'b011: not_y = 0;
            3'b100: not_y = 1;
            3'b101: not_y = 0;
            3'b110: not_y = 1;
            3'b111: not_y = 0;
            default: not_y = 0; // Default case
        endcase
    end
endmodule
